Q.gop_relation = Q.dvp_relation;
Q.nusj_relation = Q.dnvp_relation;
Q.silver_legion_relation = Q.nsdap_relation;
Q.new_deal_liberal_strength = Q.left_strength;
Q.party_regular_strength = Q.center_strength;
Q.labor_dem_strength = Q.labor_strength;
Q.conservative_dem_strength = Q.reformist_strength;
Q.southern_dem_strength = Q.neorevisionist_strength;
Q.new_deal_liberal_dissent = Q.left_dissent;
Q.party_regular_dissent = Q.center_dissent;
Q.labor_dem_dissent = Q.labor_dissent;
Q.conservative_dem_dissent = Q.reformist_dissent;
Q.southern_dem_dissent = Q.neorevisionist_dissent;


// set faction strength/dissent to 0
for (var c of Q.factions) {
    if (Q[c+'_dissent'] < 0) {
        Q[c+'_dissent'] = 0;
    } else if (Q[c+'_dissent'] >= 100) {
        Q[c+'_dissent'] = 99;
    }
    if (Q[c+'_strength'] < 0) {
        Q[c+'_strength'] = 0;
    }
}

if (Q.unemployed <= 1) {
    Q.unemployed = 1;
}

// re-calculate dissent.
var total_strength = Q.left_strength + Q.center_strength + Q.labor_strength + Q.reformist_strength + Q.neorevisionist_strength;

// normalize strength for the different factions
Q.left_strength = 100*Q.left_strength/total_strength;
Q.center_strength = 100*Q.center_strength/total_strength;
Q.labor_strength = 100*Q.labor_strength/total_strength;
Q.reformist_strength = 100*Q.reformist_strength/total_strength;
Q.neorevisionist_strength = 100*Q.neorevisionist_strength/total_strength;
Q.new_deal_liberal_strength = Q.left_strength;
Q.party_regular_strength = Q.center_strength;
Q.labor_dem_strength = Q.labor_strength;
Q.conservative_dem_strength = Q.reformist_strength;
Q.southern_dem_strength = Q.neorevisionist_strength;
Q.new_deal_liberal_dissent = Q.left_dissent;
Q.party_regular_dissent = Q.center_dissent;
Q.labor_dem_dissent = Q.labor_dissent;
Q.conservative_dem_dissent = Q.reformist_dissent;
Q.southern_dem_dissent = Q.neorevisionist_dissent;

var total_dissent = Q.left_strength*Q.left_dissent + Q.center_strength*Q.center_dissent + Q.labor_strength*Q.labor_dissent + Q.reformist_strength*Q.reformist_dissent + Q.neorevisionist_strength*Q.neorevisionist_dissent;


Q.dissent = 0.01*total_dissent/total_strength;
Q.dissent_percent = Q.dissent*100;
console.log('new dissent: ' + Q.dissent);

if (Q.dissent < 0) {
    Q.dissent = 0;
} else if (Q.dissent > 0.95) {
    Q.dissent = 0.95;
}

// 1. update dates
if (Q.month_actions >= 1) {
    Q.time += 1;
    Q.month_actions = 0;
    Q.month += 1;
    if (Q.month >= 13) {
        Q.month = 1;
        Q.year += 1;
        if (Q.historical_mode) {
            Q.resources += 2;
        }
    }
    // decrement timers
    for (timer of Q.timers) {
        if (Q[timer+'_timer'] && Q[timer+'_timer'] > 0) {
            Q[timer+'_timer'] -= 1;
        }
    }
    // append to historical party support records
    var party_support_results = {'date': new Date(Q.year, Q.month - 1)};
    for (var party of Q.parties) {
        party_support_results[party] = Q[party + '_normalized']*100;
    }
    Q.party_support_records.push(party_support_results);
    Q.economic_records.push({'date': new Date(Q.year, Q.month - 1),
                             'inflation': Q.inflation,
                             'unemployment': Q.unemployed});
    // recurring party conferences: Democrats in January, GOP in February, every two years.
    if (Q.year >= 1933 && Q.month == 1) {
        if (!Q.dem_conference_seen || (Q.year - Q.last_dem_conference_year) >= 2) {
            Q.dem_conference_due = 1;
        }
    }
    if (Q.year >= 1933 && Q.month == 2) {
        if (!Q.gop_conference_seen || (Q.year - Q.last_gop_conference_year) >= 2) {
            Q.gop_conference_due = 1;
        }
    }
    // legislative support model: House coalitions for Speaker/governing capacity,
    // Senate coalitions for bill passage and sustained policy throughput.
    // Relations now erode coalition support in each chamber instead of only gating
    // coalition formation menus. The House is more sensitive to party discipline;
    // the Senate is more sensitive to individual allied senators defecting.
    var relationFactor = function(relation, floor, ceiling) {
        var r = relation || 0;
        if (r <= floor) {
            return 0;
        }
        if (r >= ceiling) {
            return 1;
        }
        return (r - floor) / (ceiling - floor);
    };
    var houseAlly = function(votes, relation, floor, ceiling) {
        return (votes || 0) * (0.35 + 0.65 * relationFactor(relation, floor, ceiling));
    };
    var senateAlly = function(votes, relation, floor, ceiling) {
        return (votes || 0) * (0.25 + 0.75 * relationFactor(relation, floor, ceiling));
    };
    var coalitionPenalty = Math.max(0, Q.coalition_dissent || 0) * 0.6;
    var kpdPenalty = Math.max(0, Q.kpd_coalition_dissent || 0) * 0.8;
    var weimarHouseSupport = (Q.spd_h || 0) + houseAlly(Q.z_h, Q.z_relation, 25, 60);
    var weimarSenateSupport = (Q.spd_s || 0) + senateAlly(Q.z_s, Q.z_relation, 30, 65);
    var grandHouseSupport = weimarHouseSupport + houseAlly(Q.dvp_h, Q.dvp_relation, 30, 65) + houseAlly(Q.ddp_h || 0, Q.ddp_relation, 25, 60);
    var grandSenateSupport = weimarSenateSupport + senateAlly(Q.dvp_s, Q.dvp_relation, 35, 70) + senateAlly(Q.ddp_s || 0, Q.ddp_relation, 30, 65);
    var leftHouseSupport = (Q.spd_h || 0) + houseAlly((Q.kpd_h || 0) + (Q.sapd_h || 0), Q.kpd_relation, 35, 70);
    var leftSenateSupport = (Q.spd_s || 0) + senateAlly((Q.kpd_s || 0) + (Q.sapd_s || 0), Q.kpd_relation, 40, 75);
    var popularHouseSupport = (Q.spd_h || 0) + houseAlly((Q.kpd_h || 0) + (Q.sapd_h || 0), Q.kpd_relation, 40, 70) + houseAlly(Q.z_h, Q.z_relation, 40, 70);
    var popularSenateSupport = (Q.spd_s || 0) + senateAlly((Q.kpd_s || 0) + (Q.sapd_s || 0), Q.kpd_relation, 45, 75) + senateAlly(Q.z_s, Q.z_relation, 45, 75);
    Q.effective_weimar_house = Math.max(0, weimarHouseSupport - coalitionPenalty);
    Q.effective_weimar_senate = Math.max(0, weimarSenateSupport - coalitionPenalty);
    Q.effective_grand_house = Math.max(0, grandHouseSupport - coalitionPenalty);
    Q.effective_grand_senate = Math.max(0, grandSenateSupport - coalitionPenalty);
    Q.effective_left_house = Math.max(0, leftHouseSupport - kpdPenalty);
